// Emit API v1: emit(type, payload).
// Makes an event, stores it, dispatches to the matching registered handler.
const { make } = require("./event.js");
const { Store } = require("./store.js");
const { all } = require("./index.js");

const store = new Store();

function emit(type, payload) {
  const event = make(type, payload);
  store.add(event);
  const handler = all().find((h) => h.type === type);
  if (!handler) {
    throw new Error(`no handler for type: ${type}`);
  }
  return handler.handle(event);
}

module.exports = { emit, store };
